INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-01771', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '協助經歷父母離婚兒童，下列建議何者錯誤？', '["支持家庭經濟穩定", "建議不具監護權的父母，要讓出管教空間給有監護權父母，減少和孩子的聯繫", "減少生活中的變動，不要搬家，維持和同學、朋友、老師的連結", "尋求社會支持，避免孩子成為家庭的照顧者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01772', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年發展到屬於柯博格（Kohlberg）道德習俗期，會試圖成為「他人眼中的好人」，有從眾性傾向，不 敢拒絕。協助青少年培養自己的觀點，下列敘述何者並非適當做法？', '["協助父母學習以堅定的態度回應，青少年「別人家的父母都可以，你為什麼不可以」的挑戰", "成人可以角色扮演方式，協助青少年學習如何應對同儕壓力", "當青少年主張「大家都這樣說，大家都這樣做」時，和青少年討論還有什麼其他選擇", "鼓勵青少年參加各種才藝營隊，藉以增進青少年成就感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01773', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「出櫃」是很困難的決定，代表將有一連串的問題迎面而來。沙爾曼（Sauerman）對想向父母出櫃的青 少年提出一些建議，下列何者錯誤？', '["與父母關係緊張有衝突時，不是出櫃的適當時機", "選擇先告訴父母中一人，最後還是要讓父母都知道", "向父母出櫃後，如父母有情緒反應，要立即和父母討論免得情緒積累難以處理", "開始溝通時要先告訴父母正向的想法，如他們對你很重要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01774', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '童話故事中對「後母」的描述，某程度反應繼親家庭成員複雜的「家人」關係。下列何者並非協助繼親 家庭雙親的適當建議？', '["對待不同性別繼子女方法要不同，女生不喜身體接觸，男生接受繼父母速度較快", "管教常成為繼親家庭衝突來源，要優先處理繼親子關係", "先和繼子女當朋友，管教交給原生父母", "財務共享，入住新屋有助於提升再婚夫妻的婚姻滿意度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01775', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '男性使用專業助人協助遠低於女性，除了擔心求助被視為膽怯，專業協助進行的方式可能也有影響。下 列何方式在鼓勵男性使用諮商、輔導等協助時效果相對不顯著？', '["團體形式", "工作方向聚焦在技巧的學習如情緒管理", "話題的設定與男性生活和經驗有較高的連結如運動等", "加長情緒探索時間，鼓勵男性勇敢說出感受"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01776', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '照顧罹患失智症的家人，隨著照顧時間拉長，家庭照顧者的角色、任務和專業人員快分不清。關於「照 顧」下列敘述何者錯誤？', '["照顧工作並非全然負向，照顧者也會覺得自己有用，可以回饋被照顧者", "被照顧者經歷失去獨立與執行任務能力的雙重失落，因此可能抗拒被照顧", "照顧者支持團體不一定要用面對面形式，網路也有相同效果", "當被照顧者入住機構，機構完全取代家庭照顧者，家人即可卸下所有照顧角色與任務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01777', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '2000年我國通過「安寧緩和條例」，2016年公布「病人自主權利法」，將於公布3年後施行。屆時病人 可預立醫療決定，符合五種臨床狀況時可以選擇或拒絕醫療。關於病人自主權利法下列敘述何者錯誤？', '["預立醫療決定可以撤回", "可透過選任醫療委任代理人執行自己的決定", "家屬不會因為了解病人心願，而減輕壓力，反而要提前面對死亡、選擇與醫療的有限性", "預立醫療決定等於拒絕任何形式的醫療，包括緩和醫療"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01778', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '長期照顧機構提供各式活動，「懷舊」（reminiscence）是很常見的活動主題，「懷舊」和個人生命回顧 相關，把個人的過去、現在和未來冶於一爐，下列何者內容與個人生命回顧關連較低？', '["單純的玩古早童玩、吃古早零食", "主題依個人發展時間軸線，從童年開始、直到老年期", "運用音樂與照片等輔助，協助失智長者喚起某一段生命時期經驗", "功能好的長者做口述歷史，或是畫家庭樹"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01779', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '推、打、搶玩具、破壞遊戲規則等兒童攻擊行為會困擾照顧者，下列關於兒童攻擊行為的已知發現何者 錯誤？', '["兒童性別與攻擊類型無關", "學齡前階段兒童的攻擊行為高於其他年齡，預防服務方案在5歲前就要推動", "電視的暴力節目對已有攻擊行為的兒童有較大的影響，對原本無攻擊行為的兒童幾乎無影響", "幼兒已有蓄意傷害他人的敵對性攻擊行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01780', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據艾瑞克森（Erikson）及李文生（Levinson）的理論，下列何者為瞭解成年前期發展的理論概念？', '["親密vs.疏離，生命結構（life structure）", "自我認同vs.角色混淆，生命週期（life cycle）", "自我認同vs.角色混淆，生命結構（life structure）", "親密vs.疏離，生命週期（life cycle）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
